31→  function drawStrokes(svg, opts) {
32→    opts = opts || {};
33→    const container = svg.parentElement;
34→    const w = container.offsetWidth;
35→    const h = container.offsetHeight;
36→    const filterId = opts.filterId || "strokes-warp";
37→
38→    svg.setAttribute("viewBox", `0 0 ${w} ${h}`);
39→    svg.innerHTML = "";
40→
41→    const defs = document.createElementNS("http://www.w3.org/2000/svg", "defs");
42→    defs.innerHTML = `<filter id="${filterId}">
43→      <feTurbulence type="turbulence" baseFrequency="0.04" numOctaves="2" result="turbulence" seed="${Math.floor(Math.random() * 100)}" />
44→      <feDisplacementMap in="SourceGraphic" in2="turbulence" scale="3" xChannelSelector="R" yChannelSelector="G" />
45→    </filter>`;
46→    svg.appendChild(defs);
47→
48→    const g = document.createElementNS("http://www.w3.org/2000/svg", "g");
49→    g.setAttribute("filter", `url(#${filterId})`);
50→    svg.appendChild(g);
51→
52→    const margin = opts.margin || 5;
53→    let x = margin + Math.random() * (opts.startSpread || 10);
54→
55→    while (x < w - margin) {
56→      const len = 15 + Math.random() * 60;
57→      const angle = (Math.random() - 0.5) * 2.8;
58→      const dx = Math.cos(angle) * len;
59→      const dy = Math.sin(angle) * len;
60→
61→      let startY;
62→      if (opts.yBias === "edges") {
63→        startY =
64→          Math.random() < 0.5
65→            ? Math.random() * Math.random() * h * 0.5
66→            : h - Math.random() * Math.random() * h * 0.5;
67→      } else {
68→        startY = margin + Math.random() * (h - margin * 2);
69→      }
70→
71→      const endX = x + dx;
72→      const endY = startY + dy;
73→      const t = 0.3 + Math.random() * 0.4;
74→      const mx = x + dx * t + (Math.random() - 0.5) * 12;
75→      const my = startY + dy * t + (Math.random() - 0.5) * 12;
76→      const d = `M${x} ${startY}L${mx} ${my}L${endX} ${endY}`;
77→
78→      const path = document.createElementNS(
79→        "http://www.w3.org/2000/svg",
80→        "path",
81→      );
82→      path.setAttribute("d", d);
83→      path.setAttribute("stroke", "currentColor");
