 1→<script webc:type="render" webc:is="template">
 2→  module.exports = function () {
 3→    const seededRandom = (seed) => {
 4→      let s = seed | 0;
 5→      return () => {
 6→        s = (s * 1103515245 + 12345) & 0x7fffffff;
 7→        return s / 0x7fffffff;
 8→      };
 9→    };
10→
11→    const pointsToPath = (coords, breaks) => {
12→      const n = coords.length;
13→      if (n < 2) return "";
14→      const f = (v) => v.toFixed(2);
15→
16→      let d = `M ${f(coords[0][0])} ${f(coords[0][1])}`;
17→      for (let i = 1; i < n; i++) {
18→        const cmd = breaks.has(i) ? "M" : "L";
19→        d += ` ${cmd} ${f(coords[i][0])} ${f(coords[i][1])}`;
20→      }
21→      return d;
22→    };
23→
24→    const year = parseInt(this.year) || 2024;
25→    const count = parseInt(this.count) || 8;
26→    const width = parseInt(this.width) || 250;
27→    const height = parseInt(this.height) || 25;
28→
29→    const rng = seededRandom(year * 100 + count);
30→    const numPoints = 15;
31→    const numLines = 3 + Math.floor(count * 0.4);
32→
33→    const pad = 2;
34→    const numFrames = 8;
35→
36→    const paths = [];
37→    for (let i = 0; i < numLines; i++) {
38→      const startY = rng() * height;
39→      const endY = rng() * height * 0.1;
40→
41→      // Pre-compute the fixed x and baseY for each point
42→      const base = [];
43→      for (let j = 0; j <= numPoints; j++) {
44→        const t = j / numPoints;
45→        const x = pad + t * (width - pad * 2);
46→        const baseY = startY + (endY - startY) * t;
47→        const spread = 1 - t * 0.8;
48→        base.push({ x, baseY, spread });
49→      }
50→
51→      // Pick random break points for this line
52→      const numBreaks = 1 + Math.floor(rng() * 3);
53→      const breaks = new Set();
54→      while (breaks.size < numBreaks) {
55→        const idx = 2 + Math.floor(rng() * (numPoints - 3));
56→        breaks.add(idx);
57→      }
58→
59→      // Generate wobble variations
60→      const frames = [];
61→      for (let f = 0; f < numFrames; f++) {
62→        const coords = base.map(({ x, baseY, spread }, j) => {
63→          if (j === 0 || j === numPoints) return [x, baseY];
64→          const wobble = (rng() - 0.5) * height * 0.45 * spread;
65→          const y = Math.max(pad, Math.min(height - pad, baseY + wobble));
66→          return [x, y];
67→        });
68→        frames.push(pointsToPath(coords, breaks));
69→      }
70→
71→      const strokeWidth = (0.3 + rng() * 0.5).toFixed(2);
72→      const dur = (2 + rng() * 3).toFixed(1);
73→      const values = [...frames, frames[0]].join(";");
74→      paths.push(
75→        `<path d="${frames[0]}" fill="none" stroke="currentColor" stroke-width="${strokeWidth}"><animate attributeName="d" values="${values}" dur="${dur}s" calcMode="discrete" repeatCount="indefinite" /></path>`,
76→      );
77→    }
78→
79→    const filterId = `scratch-warp-${year}`;
80→    const seed = Math.floor(rng() * 100);
81→    const defs = `<defs><filter id="${filterId}"><feTurbulence type="turbulence" baseFrequency="0.04" numOctaves="2" result="turbulence" seed="${seed}" /><feDisplacementMap in="SourceGraphic" in2="turbulence" scale="3" xChannelSelector="R" yChannelSelector="G" /></filter></defs>`;
82→
83→    return `<svg xmlns="http://www.w3.org/2000/svg" viewBox="0 0 ${width} ${height}" width="${width}" height="${height}" aria-hidden="true">${defs}<g filter="url(#${filterId})">${paths.join("")}</g></svg>`;
84→  };
85→</script>
